/**
 * Agent class - ported from pi-mono/packages/agent/src/agent.ts
 * High-level API with state management, event subscriptions, steering/follow-up queues.
 */

import {
	type ImageContent,
	type Message,
	type Model,
	streamSimple,
	type TextContent,
	type ThinkingBudgets,
	type UserContentBlock,
} from "@pie/ai";
import { agentLoop, agentLoopContinue } from "./agent-loop.js";
import type {
	AgentContext,
	AgentEvent,
	AgentLoopConfig,
	AgentMessage,
	AgentState,
	AgentHooks,
	HostSemanticEvent,
	StatusSnapshot,
	AgentTool,
	StreamFn,
	ThinkingLevel,
} from "./types.js";

function defaultConvertToLlm(messages: AgentMessage[]): Message[] {
	return messages.filter((m) => m.role === "user" || m.role === "assistant" || m.role === "toolResult");
}

function isAgentMessage(value: unknown): value is AgentMessage {
	return !!value && typeof value === "object" && "role" in value;
}

function isUserContentBlock(value: unknown): value is UserContentBlock {
	if (!value || typeof value !== "object" || !("type" in value)) {
		return false;
	}

	const type = (value as { type?: unknown }).type;
	return type === "text" || type === "image" || type === "audio" || type === "video" || type === "fileRef";
}

export interface AgentOptions {
	initialState?: Partial<AgentState>;
	convertToLlm?: (messages: AgentMessage[]) => Message[] | Promise<Message[]>;
	transformContext?: (messages: AgentMessage[], signal?: AbortSignal) => Promise<AgentMessage[]>;
	steeringMode?: "all" | "one-at-a-time";
	followUpMode?: "all" | "one-at-a-time";
	streamFn?: StreamFn;
	sessionId?: string;
	apiKey?: string;
	getApiKey?: (provider: string) => Promise<string | undefined> | string | undefined;
	thinkingBudgets?: ThinkingBudgets;
	maxRetryDelayMs?: number;
}

export class Agent {
	private _state: AgentState;
	private listeners = new Set<(e: AgentEvent) => void>();
	private semanticListeners = new Set<(e: HostSemanticEvent) => void>();
	private abortController?: AbortController;
	private convertToLlm: (messages: AgentMessage[]) => Message[] | Promise<Message[]>;
	private transformContext?: (messages: AgentMessage[], signal?: AbortSignal) => Promise<AgentMessage[]>;
	private steeringQueue: AgentMessage[] = [];
	private followUpQueue: AgentMessage[] = [];
	private steeringMode: "all" | "one-at-a-time";
	private followUpMode: "all" | "one-at-a-time";
	public streamFn: StreamFn;
	private _sessionId?: string;
	private _apiKey?: string;
	public getApiKey?: (provider: string) => Promise<string | undefined> | string | undefined;
	private runningPrompt?: Promise<void>;
	private resolveRunningPrompt?: () => void;
	private _thinkingBudgets?: ThinkingBudgets;
	private _maxRetryDelayMs?: number;
	private hooks?: AgentHooks;
	private statusSnapshot: StatusSnapshot = {
		phase: "idle",
		turnState: "completed",
		hasPendingToolContinuation: false,
	};

	constructor(opts: AgentOptions = {}) {
		this._state = {
			systemPrompt: "",
			model: null as any, // Must be set before use
			thinkingLevel: "off",
			tools: [],
			messages: [],
			isStreaming: false,
			streamMessage: null,
			pendingToolCalls: new Set<string>(),
			error: undefined,
			...opts.initialState,
		};
		this.convertToLlm = opts.convertToLlm || defaultConvertToLlm;
		this.transformContext = opts.transformContext;
		this.steeringMode = opts.steeringMode || "one-at-a-time";
		this.followUpMode = opts.followUpMode || "one-at-a-time";
		this.streamFn = opts.streamFn || streamSimple;
		this._sessionId = opts.sessionId;
		this._apiKey = opts.apiKey;
		this.getApiKey = opts.getApiKey;
		this._thinkingBudgets = opts.thinkingBudgets;
		this._maxRetryDelayMs = opts.maxRetryDelayMs;
		this.hooks = opts.initialState?.hooks;
	}

	get sessionId(): string | undefined {
		return this._sessionId;
	}
	set sessionId(value: string | undefined) {
		this._sessionId = value;
	}

	get apiKey(): string | undefined {
		return this._apiKey;
	}
	set apiKey(value: string | undefined) {
		this._apiKey = value;
	}

	get thinkingBudgets(): ThinkingBudgets | undefined {
		return this._thinkingBudgets;
	}
	set thinkingBudgets(value: ThinkingBudgets | undefined) {
		this._thinkingBudgets = value;
	}

	get maxRetryDelayMs(): number | undefined {
		return this._maxRetryDelayMs;
	}
	set maxRetryDelayMs(value: number | undefined) {
		this._maxRetryDelayMs = value;
	}

	get state(): AgentState {
		return this._state;
	}

	subscribe(fn: (e: AgentEvent) => void): () => void {
		this.listeners.add(fn);
		return () => this.listeners.delete(fn);
	}

	subscribeSemantic(fn: (e: HostSemanticEvent) => void): () => void {
		this.semanticListeners.add(fn);
		return () => this.semanticListeners.delete(fn);
	}

	getStatusSnapshot(): StatusSnapshot {
		return { ...this.statusSnapshot };
	}

	setSystemPrompt(v: string) {
		this._state.systemPrompt = v;
	}
	setModel(m: Model<any>) {
		this._state.model = m;
	}
	setThinkingLevel(l: ThinkingLevel) {
		this._state.thinkingLevel = l;
	}
	setTools(t: AgentTool<any>[]) {
		this._state.tools = t;
	}
	setHooks(hooks: AgentHooks | undefined) {
		this.hooks = hooks;
	}

	replaceMessages(ms: AgentMessage[]) {
		this._state.messages = ms.slice();
	}
	appendMessage(m: AgentMessage) {
		this._state.messages = [...this._state.messages, m];
	}
	clearMessages() {
		this._state.messages = [];
	}

	steer(m: AgentMessage) {
		this.steeringQueue.push(m);
	}
	followUp(m: AgentMessage) {
		this.followUpQueue.push(m);
	}
	clearSteeringQueue() {
		this.steeringQueue = [];
	}
	clearFollowUpQueue() {
		this.followUpQueue = [];
	}
	clearAllQueues() {
		this.steeringQueue = [];
		this.followUpQueue = [];
	}
	hasQueuedMessages(): boolean {
		return this.steeringQueue.length > 0 || this.followUpQueue.length > 0;
	}
	setSteeringMode(mode: "all" | "one-at-a-time") {
		this.steeringMode = mode;
	}
	getSteeringMode(): "all" | "one-at-a-time" {
		return this.steeringMode;
	}
	setFollowUpMode(mode: "all" | "one-at-a-time") {
		this.followUpMode = mode;
	}
	getFollowUpMode(): "all" | "one-at-a-time" {
		return this.followUpMode;
	}

	private dequeueSteeringMessages(): AgentMessage[] {
		if (this.steeringMode === "one-at-a-time") {
			if (this.steeringQueue.length > 0) {
				const first = this.steeringQueue[0];
				this.steeringQueue = this.steeringQueue.slice(1);
				return [first];
			}
			return [];
		}
		const steering = this.steeringQueue.slice();
		this.steeringQueue = [];
		return steering;
	}

	private dequeueFollowUpMessages(): AgentMessage[] {
		if (this.followUpMode === "one-at-a-time") {
			if (this.followUpQueue.length > 0) {
				const first = this.followUpQueue[0];
				this.followUpQueue = this.followUpQueue.slice(1);
				return [first];
			}
			return [];
		}
		const followUp = this.followUpQueue.slice();
		this.followUpQueue = [];
		return followUp;
	}

	abort() {
		this.abortController?.abort();
	}
	waitForIdle(): Promise<void> {
		return this.runningPrompt ?? Promise.resolve();
	}
	reset() {
		this._state.messages = [];
		this._state.isStreaming = false;
		this._state.streamMessage = null;
		this._state.pendingToolCalls = new Set<string>();
		this._state.error = undefined;
		this.steeringQueue = [];
		this.followUpQueue = [];
		this.runningPrompt = undefined;
		this.resolveRunningPrompt = undefined;
		this.updateStatusSnapshot({
			phase: "idle",
			turnState: "completed",
			activeToolName: undefined,
			lastStopReason: undefined,
			hasPendingToolContinuation: false,
		});
	}
	/**
	 * Reset only the processing state without clearing messages.
	 * Useful when resuming a session that was saved mid-processing.
	 */
	resetProcessingState() {
		this._state.isStreaming = false;
		this._state.streamMessage = null;
		this._state.pendingToolCalls = new Set<string>();
		this._state.error = undefined;
		this.steeringQueue = [];
		this.followUpQueue = [];
		this.runningPrompt = undefined;
		this.resolveRunningPrompt = undefined;
		this.abortController = undefined;
		this.updateStatusSnapshot({
			phase: "idle",
			turnState: "completed",
			activeToolName: undefined,
			lastStopReason: undefined,
			hasPendingToolContinuation: false,
		});
	}

	async prompt(message: AgentMessage | AgentMessage[]): Promise<void>;
	async prompt(content: UserContentBlock[]): Promise<void>;
	async prompt(input: string, images?: ImageContent[]): Promise<void>;
	async prompt(input: string | AgentMessage | AgentMessage[] | UserContentBlock[], images?: ImageContent[]) {
		// IMMEDIATELY set runningPrompt to prevent race conditions
		// This must happen BEFORE any async operations
		if (this.runningPrompt) {
			throw new Error("Agent is already processing a prompt.");
		}
		if (this._state.isStreaming) {
			throw new Error("Agent is already processing a prompt.");
		}

		// Create the runningPrompt promise IMMEDIATELY (synchronously)
		// to block any concurrent calls
		const promise = new Promise<void>((resolve) => {
			this.resolveRunningPrompt = resolve;
		});
		this.runningPrompt = promise;

		try {
			const model = this._state.model;
			if (!model) throw new Error("No model configured");

			let msgs: AgentMessage[];

			if (Array.isArray(input)) {
				if (input.length > 0 && input.every((item) => isUserContentBlock(item))) {
					msgs = [{ role: "user", content: input, timestamp: Date.now() }];
				} else if (input.every((item) => isAgentMessage(item))) {
					msgs = input;
				} else {
					throw new Error("Invalid prompt array: expected user content blocks or agent messages.");
				}
			} else if (typeof input === "string") {
				const content: Array<TextContent | ImageContent> = [{ type: "text", text: input }];
				if (images && images.length > 0) {
					content.push(...images);
				}
				msgs = [{ role: "user", content, timestamp: Date.now() }];
			} else {
				msgs = [input];
			}

			await this._runLoop(msgs);
		} finally {
			// Only clear if it's still our promise
			if (this.runningPrompt === promise) {
				this.resolveRunningPrompt?.();
				this.runningPrompt = undefined;
				this.resolveRunningPrompt = undefined;
			}
		}
	}

	async continue() {
		// IMMEDIATELY check and set runningPrompt to prevent race conditions
		if (this.runningPrompt) {
			throw new Error("Agent is already processing.");
		}
		if (this._state.isStreaming) {
			throw new Error("Agent is already processing.");
		}

		// Create the runningPrompt promise IMMEDIATELY (synchronously)
		const promise = new Promise<void>((resolve) => {
			this.resolveRunningPrompt = resolve;
		});
		this.runningPrompt = promise;

		try {
			const messages = this._state.messages;
			if (messages.length === 0) {
				throw new Error("No messages to continue from");
			}
			if (messages[messages.length - 1].role === "assistant") {
				const queuedSteering = this.dequeueSteeringMessages();
				if (queuedSteering.length > 0) {
					await this._runLoop(queuedSteering, { skipInitialSteeringPoll: true });
					return;
				}
				const queuedFollowUp = this.dequeueFollowUpMessages();
				if (queuedFollowUp.length > 0) {
					await this._runLoop(queuedFollowUp);
					return;
				}
				throw new Error("Cannot continue from message role: assistant");
			}

			await this._runLoop(undefined);
		} finally {
			// Only clear if it's still our promise
			if (this.runningPrompt === promise) {
				this.resolveRunningPrompt?.();
				this.runningPrompt = undefined;
				this.resolveRunningPrompt = undefined;
			}
		}
	}

	private async _runLoop(messages?: AgentMessage[], options?: { skipInitialSteeringPoll?: boolean }) {
		const model = this._state.model;
		if (!model) throw new Error("No model configured");

		// NOTE: runningPrompt is now set by prompt() method synchronously
		// to prevent race conditions. We don't set it here anymore.

		this.abortController = new AbortController();
		this._state.isStreaming = true;
		this._state.streamMessage = null;
		this._state.error = undefined;

		const reasoning = this._state.thinkingLevel === "off" ? undefined : this._state.thinkingLevel;

		const context: AgentContext = {
			systemPrompt: this._state.systemPrompt,
			messages: this._state.messages.slice(),
			tools: this._state.tools,
		};

		let skipInitialSteeringPoll = options?.skipInitialSteeringPoll === true;

		const config: AgentLoopConfig = {
			model,
			reasoning,
			apiKey: this._apiKey,
			sessionId: this._sessionId,
			thinkingBudgets: this._thinkingBudgets,
			maxRetryDelayMs: this._maxRetryDelayMs,
			convertToLlm: this.convertToLlm,
			transformContext: this.transformContext,
			getApiKey: this.getApiKey,
			hooks: this.hooks,
			getSteeringMessages: async () => {
				if (skipInitialSteeringPoll) {
					skipInitialSteeringPoll = false;
					return [];
				}
				return this.dequeueSteeringMessages();
			},
			getFollowUpMessages: async () => this.dequeueFollowUpMessages(),
		};

		let partial: AgentMessage | null = null;

		try {
			const stream = messages
				? agentLoop(messages, context, config, this.abortController.signal, this.streamFn)
				: agentLoopContinue(context, config, this.abortController.signal, this.streamFn);

			for await (const event of stream) {
				switch (event.type) {
					case "message_start":
						partial = event.message;
						this._state.streamMessage = event.message;
						break;
					case "message_update":
						partial = event.message;
						this._state.streamMessage = event.message;
						break;
					case "message_end":
						partial = null;
						this._state.streamMessage = null;
						this.appendMessage(event.message);
						break;
					case "tool_execution_start": {
						const s = new Set(this._state.pendingToolCalls);
						s.add(event.toolCallId);
						this._state.pendingToolCalls = s;
						break;
					}
					case "tool_execution_end": {
						const s = new Set(this._state.pendingToolCalls);
						s.delete(event.toolCallId);
						this._state.pendingToolCalls = s;
						break;
					}
					case "turn_end":
						if (event.message.role === "assistant" && (event.message as any).errorMessage) {
							this._state.error = (event.message as any).errorMessage;
						}
						break;
					case "agent_end":
						this._state.isStreaming = false;
						this._state.streamMessage = null;
						break;
				}

				this.emit(event);
			}

			if (partial && partial.role === "assistant" && (partial as any).content?.length > 0) {
				const onlyEmpty = !(partial as any).content.some(
					(c: any) =>
						(c.type === "thinking" && c.thinking?.trim().length > 0) ||
						(c.type === "text" && c.text?.trim().length > 0) ||
						(c.type === "toolCall" && c.name?.trim().length > 0),
				);
				if (!onlyEmpty) {
					this.appendMessage(partial);
				}
			}
		} catch (err: any) {
			const errorMsg: AgentMessage = {
				role: "assistant",
				content: [{ type: "text", text: "" }],
				api: model.api,
				provider: model.provider,
				model: model.id,
				usage: {
					input: 0, output: 0, cacheRead: 0, cacheWrite: 0, totalTokens: 0,
					cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0, total: 0 },
				},
				stopReason: this.abortController?.signal.aborted ? "aborted" : "error",
				errorMessage: err?.message || String(err),
				timestamp: Date.now(),
			} as AgentMessage;

			this.appendMessage(errorMsg);
			this._state.error = err?.message || String(err);
			this.emit({ type: "agent_end", messages: [errorMsg] });
		} finally {
			this._state.isStreaming = false;
			this._state.streamMessage = null;
			this._state.pendingToolCalls = new Set<string>();
			this.abortController = undefined;
			// NOTE: runningPrompt is now managed by prompt() and continue() methods
			// to ensure it's set synchronously. We don't clean it up here anymore.
		}
	}

	private emit(e: AgentEvent) {
		for (const listener of this.listeners) {
			listener(e);
		}
		this.emitDerivedSemanticEvents(e);
	}

	private emitSemantic(e: HostSemanticEvent) {
		for (const listener of this.semanticListeners) {
			listener(e);
		}
	}

	private updateStatusSnapshot(next: Partial<StatusSnapshot>) {
		const snapshot: StatusSnapshot = {
			...this.statusSnapshot,
			...next,
		};
		if (
			snapshot.phase === this.statusSnapshot.phase &&
			snapshot.turnState === this.statusSnapshot.turnState &&
			snapshot.activeToolName === this.statusSnapshot.activeToolName &&
			snapshot.lastStopReason === this.statusSnapshot.lastStopReason &&
			snapshot.hasPendingToolContinuation === this.statusSnapshot.hasPendingToolContinuation
		) {
			return;
		}
		this.statusSnapshot = snapshot;
		this.emitSemantic({ type: "status_snapshot_changed", snapshot: { ...snapshot } });
	}

	private emitDerivedSemanticEvents(event: AgentEvent) {
		switch (event.type) {
			case "message_start":
				if (event.message.role === "assistant") {
					this.updateStatusSnapshot({
						phase: "responding",
						turnState: "continuing",
						activeToolName: undefined,
						lastStopReason: undefined,
						hasPendingToolContinuation: false,
					});
					this.emitSemantic({ type: "assistant_response_started", message: event.message });
				}
				break;
			case "message_update":
				if (
					event.message.role === "assistant" &&
					event.assistantMessageEvent.type === "text_delta"
				) {
					this.updateStatusSnapshot({ phase: "responding" });
					this.emitSemantic({
						type: "assistant_response_delta",
						message: event.message,
						delta: event.assistantMessageEvent.delta,
					});
				}
				break;
			case "message_end":
				if (event.message.role === "assistant") {
					this.emitSemantic({ type: "assistant_response_finished", message: event.message });
				}
				break;
			case "tool_execution_start":
				this.updateStatusSnapshot({
					phase: "running_tool",
					turnState: "continuing",
					activeToolName: event.toolName,
					lastStopReason: undefined,
					hasPendingToolContinuation: false,
				});
				this.emitSemantic({
					type: "tool_started",
					toolCallId: event.toolCallId,
					toolName: event.toolName,
					args: event.args,
				});
				break;
			case "tool_execution_update":
				this.emitSemantic({
					type: "tool_progressed",
					toolCallId: event.toolCallId,
					toolName: event.toolName,
					args: event.args,
					partialResult: event.partialResult,
				});
				break;
			case "tool_execution_end":
				this.updateStatusSnapshot({
					phase: this._state.isStreaming ? "responding" : "completed",
					activeToolName: undefined,
				});
				this.emitSemantic({
					type: "tool_finished",
					toolCallId: event.toolCallId,
					toolName: event.toolName,
					args: event.args,
					result: event.result,
					isError: event.isError,
				});
				break;
			case "turn_end": {
				const stopReason =
					event.message.role === "assistant" ? event.message.stopReason : undefined;
				if (stopReason === "toolUse") {
					this.updateStatusSnapshot({
						phase: "responding",
						turnState: "continuing",
						lastStopReason: stopReason,
						hasPendingToolContinuation: true,
						activeToolName: undefined,
					});
					this.emitSemantic({
						type: "turn_continues",
						message: event.message,
						toolResults: event.toolResults,
					});
				} else if (stopReason === "error" || stopReason === "aborted") {
					this.updateStatusSnapshot({
						phase: "failed",
						turnState: "failed",
						lastStopReason: stopReason,
						hasPendingToolContinuation: false,
						activeToolName: undefined,
					});
					this.emitSemantic({
						type: "turn_failed",
						message: event.message,
						toolResults: event.toolResults,
					});
				} else {
					this.updateStatusSnapshot({
						phase: "completed",
						turnState: "completed",
						lastStopReason: stopReason,
						hasPendingToolContinuation: false,
						activeToolName: undefined,
					});
					this.emitSemantic({
						type: "turn_completed",
						message: event.message,
						toolResults: event.toolResults,
					});
				}
				break;
			}
			case "agent_end": {
				const lastMessage = event.messages[event.messages.length - 1];
				if (
					lastMessage?.role === "assistant" &&
					(lastMessage.stopReason === "error" || lastMessage.stopReason === "aborted")
				) {
					this.updateStatusSnapshot({
						phase: "failed",
						turnState: "failed",
						lastStopReason: lastMessage.stopReason,
						hasPendingToolContinuation: false,
						activeToolName: undefined,
					});
					this.emitSemantic({
						type: "turn_failed",
						message: lastMessage,
						toolResults: [],
					});
				}
				this.updateStatusSnapshot({
					phase: "idle",
					activeToolName: undefined,
					hasPendingToolContinuation: false,
				});
				break;
			}
		}
	}
}
