import type { SkillRegistryEntry } from "@pie/agent-framework";
import { Type } from "@sinclair/typebox";
import { defineSharedCapability } from "./capability.js";

export interface ResolvedSkillContent {
	name: string;
	source: string;
	content: string;
}

export interface ReadSkillCapabilityDeps {
	resolveSkill?(name: string): ResolvedSkillContent | null | Promise<ResolvedSkillContent | null>;
	skillLoader?: {
		getSkill?(name: string): SkillRegistryEntry | null | undefined;
		loadSkill?(name: string): SkillRegistryEntry | null | undefined;
	};
}

export const ReadSkillParamsSchema = Type.Object({
	name: Type.String({ description: "Exact skill name from the available_skills list." }),
});

export function createReadSkillCapability(deps: ReadSkillCapabilityDeps) {
	async function resolveSkill(name: string): Promise<ResolvedSkillContent | null> {
		if (deps.resolveSkill) {
			return deps.resolveSkill(name);
		}

		const skill = deps.skillLoader?.getSkill?.(name) ?? deps.skillLoader?.loadSkill?.(name);
		if (!skill) {
			return null;
		}

		return {
			name: skill.name,
			source: skill.filePath || "skill-registry",
			content: skill.prompt,
		};
	}

	const tool = {
		name: "read_skill",
		label: "read_skill",
		description: "Load the full contents of a builtin or project skill by exact name.",
		parameters: ReadSkillParamsSchema,
		async execute(toolCallIdOrArgs: string | { name: string }, maybeArgs?: { name: string }) {
			const args = typeof toolCallIdOrArgs === "string" ? maybeArgs : toolCallIdOrArgs;
			const skillName = String(args?.name || "").trim();
			const skill = await resolveSkill(skillName);
			if (!skill?.content) {
				return {
					content: [{ type: "text" as const, text: `Skill not found: ${skillName || "(empty)"}` }],
					details: { found: false, name: skillName || undefined },
					isError: true,
				};
			}

			return {
				content: [{
					type: "text" as const,
					text: `# ${skill.name}\nsource: ${skill.source}\n\n${skill.content}`,
				}],
				details: { found: true, name: skill.name, source: skill.source },
			};
		},
	};

	return {
		...defineSharedCapability({
			id: "read-skill",
			description: "Shared capability for loading full skill contents through a host-provided skill resolver.",
			tools: [tool],
		}),
		tool,
	};
}
