export * from "./capability.js";
export * from "./plan.js";
export * from "./read-skill.js";
export * from "./subagent.js";
export * from "./todo.js";
export * from "./ask-user.js";
export * from "./builtin/fs/index.js";

import {
	collectSharedCapabilityPromptAdditions,
	type SharedCapabilityDefinition,
} from "./capability.js";
import { createAskUserCapability } from "./ask-user.js";
import { createManageTodoCapability } from "./todo.js";

export function getSharedCapabilityPromptAdditionsForToolNames(toolNames: readonly string[]): string[] {
	const definitions: SharedCapabilityDefinition<any>[] = [
		createManageTodoCapability(),
		createAskUserCapability(),
	];
	return collectSharedCapabilityPromptAdditions(
		definitions,
		toolNames,
	);
}
