import type { AgentTool } from "@pie/agent-core";
import { createReadSkillCapability } from "@pie/shared-headless-capabilities";
import { createUnitySkillLoader } from "../skills.js";

export function createReadSkillTool(projectRoot: string): AgentTool {
  const loader = createUnitySkillLoader(projectRoot);
  const capability = createReadSkillCapability({
    skillLoader: loader,
  });
  return capability.tool;
}
