// ─── Environment ──────────────────────────────────────────────────────────────

const bridge = (globalThis as any).pieBridge;
if (!bridge) throw new Error("[pie] globalThis.pieBridge not found — was PieBridge.cs initialized?");

bridge.devRpc = {
  call(method: string, args: any = {}) {
    const raw = bridge.callHost?.("pie.dev_rpc", {
      method,
      argsJson: JSON.stringify(args ?? {}),
    });
    const response = typeof raw === "string" ? JSON.parse(raw || "null") : raw;
    if (!response?.ok) {
      throw new Error(String(response?.error || `pie.dev_rpc failed: ${method}`));
    }
    return response.resultJson ? JSON.parse(response.resultJson) : null;
  },
};

const projectRoot: string = bridge.getProjectRoot();
const isEditor: boolean = bridge.isEditor === true;
const persistentDataPath: string = typeof bridge.getPersistentDataPath === "function"
  ? String(bridge.getPersistentDataPath() || "").replace(/\\/g, "/")
  : "";

