/**
 * Codex-style context compaction for long sessions.
 *
 * Instead of preserving the full transcript, compaction generates a checkpoint
 * handoff summary and replaces most of the history with:
 * - a few recent real user messages
 * - one compact summary message with a stable prefix
 */

import type { AgentMessage } from "@pie/agent-core";
import { streamSimple, type AssistantMessage, type ImageContent, type Model, type TextContent } from "@pie/ai";
import type { SessionEntry } from "./types.js";

export interface CompactionConfig {
  /** Max messages before triggering compaction */
  maxMessages: number;
  /** Max tokens before triggering compaction */
  maxTokens: number;
  /** Number of real user messages to keep before the compact summary */
  keepRecentUserMessages: number;
  /** Approximate token budget for retained user messages */
  maxRetainedUserTokens: number;
  /** Whether to enable auto-compaction */
  autoCompact: boolean;
  /** Optional token threshold reserved for future auto-compact wiring */
  autoCompactTokenLimit?: number;
  /** Optional prompt override */
  compactPrompt?: string;
  /** Optional compact summary prefix override */
  summaryPrefix?: string;
}

export const COMPACT_PROMPT = `You are performing a CONTEXT CHECKPOINT COMPACTION. Create a handoff summary for another LLM that will resume the task.

Include:
- Current progress and key decisions made
- Important context, constraints, or user preferences
- What remains to be done (clear next steps)
- Any critical data, examples, or references needed to continue

Be concise, structured, and focused on helping the next LLM seamlessly continue the work.`;

export const SUMMARY_PREFIX = `Another language model started to solve this problem and produced a summary of its thinking process. You also have access to the state of the tools that were used by that language model. Use this to build on the work that has already been done and avoid duplicating work. Here is the summary produced by the other language model, use the information in this summary to assist with your own analysis:`;

export const DEFAULT_COMPACTION_CONFIG: CompactionConfig = {
  maxMessages: 100,
  maxTokens: 8000,
  keepRecentUserMessages: 3,
  maxRetainedUserTokens: 20_000,
  autoCompact: true,
  autoCompactTokenLimit: undefined,
  compactPrompt: COMPACT_PROMPT,
  summaryPrefix: SUMMARY_PREFIX,
};

export interface CompactionEntry {
  type: "compaction";
  id: string;
  timestamp: number;
  summary: string;
  firstKeptEntryId: string;
  tokensBefore: number;
  tokensAfter: number;
}

export interface CompactionResult {
  compacted: boolean;
  summary?: string;
  messages: AgentMessage[];
  removedCount: number;
  tokenSavings: number;
  firstKeptEntryId?: string | null;
}

export interface CodexStyleCompactionOptions extends Partial<CompactionConfig> {
  model?: Model<any>;
  apiKey?: string;
  systemPrompt?: string;
  tools?: unknown[];
  signal?: AbortSignal;
}

export function estimateTokens(message: AgentMessage): number {
  const text = getMessageText(message);
  return Math.ceil(text.length / 4);
}

export function calculateTotalTokens(messages: AgentMessage[]): number {
  return messages.reduce((sum, m) => sum + estimateTokens(m), 0);
}

export function shouldCompact(
  messages: AgentMessage[],
  config: Partial<CompactionConfig> = {},
  tokenUsage?: number | null,
  modelContextWindow?: number,
): { shouldCompact: boolean; reason?: string } {
  const fullConfig = { ...DEFAULT_COMPACTION_CONFIG, ...config };

  if (messages.length > fullConfig.maxMessages) {
    return {
      shouldCompact: true,
      reason: `Message count (${messages.length}) exceeds limit (${fullConfig.maxMessages})`,
    };
  }

  const tokens = tokenUsage ?? calculateTotalTokens(messages);
  const effectiveLimit = modelContextWindow && fullConfig.autoCompactTokenLimit
    ? Math.min(fullConfig.autoCompactTokenLimit, Math.floor(modelContextWindow * 0.9))
    : fullConfig.autoCompactTokenLimit;
  const limit = effectiveLimit ?? fullConfig.maxTokens;

  if (tokens > limit) {
    return {
      shouldCompact: true,
      reason: `Token count (${tokens}) exceeds limit (${limit})`,
    };
  }

  return { shouldCompact: false };
}

export function isCompactSummaryMessage(message: string, summaryPrefix = SUMMARY_PREFIX): boolean {
  return message.startsWith(`${summaryPrefix}\n`);
}

export function formatCompactSummaryText(summaryText: string, summaryPrefix = SUMMARY_PREFIX): string {
  const compactSummary = summaryText.trim() || "(no summary available)";
  return `${summaryPrefix}\n${compactSummary}`;
}

export function collectRealUserMessages(
  messages: AgentMessage[],
  summaryPrefix = SUMMARY_PREFIX,
): string[] {
  return messages
    .filter((message): message is Extract<AgentMessage, { role: "user" }> => message.role === "user")
    .map((message) => getUserMessageText(message))
    .filter((text): text is string => Boolean(text))
    .filter((text) => !isCompactSummaryMessage(text, summaryPrefix))
    .filter((text) => !isSyntheticUserEnvelope(text));
}

export function buildCompactedHistory(
  userMessages: string[],
  summaryText: string,
  options: Partial<CompactionConfig> = {},
): AgentMessage[] {
  const fullConfig = { ...DEFAULT_COMPACTION_CONFIG, ...options };
  const keepCount = Math.max(0, fullConfig.keepRecentUserMessages);
  const recentMessages = keepCount > 0 ? userMessages.slice(-keepCount) : [];
  const retainedMessages = applyUserTokenBudget(recentMessages, fullConfig.maxRetainedUserTokens);
  const prefixedSummary = formatCompactSummaryText(summaryText, fullConfig.summaryPrefix ?? SUMMARY_PREFIX);

  const result: AgentMessage[] = retainedMessages.map((text, index) => ({
    role: "user",
    content: [{ type: "text", text }],
    timestamp: Date.now() + index,
  }));

  result.push({
    role: "user",
    content: [{ type: "text", text: prefixedSummary }],
    timestamp: Date.now() + result.length,
  });

  return result;
}

export function findFirstKeptUserEntryId(
  entries: SessionEntry[],
  options: Partial<CompactionConfig> = {},
): string | null {
  const fullConfig = { ...DEFAULT_COMPACTION_CONFIG, ...options };
  const keepCount = Math.max(0, fullConfig.keepRecentUserMessages);
  if (keepCount <= 0 || entries.length === 0) {
    return null;
  }

  const userEntries = entries
    .filter((entry): entry is SessionEntry & { message: Extract<AgentMessage, { role: "user" }> } =>
      entry.type === "message" && !!entry.message && entry.message.role === "user")
    .map((entry) => ({ entryId: entry.id, text: getUserMessageText(entry.message) }))
    .filter((entry) => Boolean(entry.text))
    .filter((entry) => !isCompactSummaryMessage(entry.text, fullConfig.summaryPrefix ?? SUMMARY_PREFIX))
    .filter((entry) => !isSyntheticUserEnvelope(entry.text));

  if (userEntries.length === 0) {
    return null;
  }

  const recentEntries = userEntries.slice(-keepCount);
  const retainedEntries = applyUserEntryTokenBudget(recentEntries, fullConfig.maxRetainedUserTokens);
  return retainedEntries[0]?.entryId ?? null;
}

export async function createCompactionSummary(
  messages: AgentMessage[],
  options: CodexStyleCompactionOptions = {},
): Promise<string> {
  const { model, apiKey, systemPrompt, compactPrompt, signal } = options;

  if (!model) {
    return createSimpleSummary(messages);
  }

  try {
    const response = await streamSimple(
      model,
      {
        systemPrompt,
        messages: [
          ...messages.filter(isCompactionCompatibleMessage),
          {
            role: "user",
            content: [{ type: "text", text: compactPrompt ?? COMPACT_PROMPT }],
            timestamp: Date.now(),
          },
        ],
      },
      {
        apiKey,
        signal,
      },
    ).result();

    return getAssistantText(response) || createSimpleSummary(messages);
  } catch (error) {
    console.warn("[Compaction] Failed to create Codex-style summary:", error);
    return createSimpleSummary(messages);
  }
}

export async function runCompact(
  messages: AgentMessage[],
  options: CodexStyleCompactionOptions = {},
): Promise<{ summary: string; messages: AgentMessage[]; removedCount: number; tokenSavings: number; firstKeptEntryId: string | null }> {
  const tokensBefore = calculateTotalTokens(messages);
  const summary = await createCompactionSummary(messages, options);
  const userMessages = collectRealUserMessages(messages, options.summaryPrefix);
  const compactedMessages = buildCompactedHistory(userMessages, summary, options);
  const tokensAfter = calculateTotalTokens(compactedMessages);

  return {
    summary,
    messages: compactedMessages,
    removedCount: Math.max(0, messages.length - compactedMessages.length),
    tokenSavings: Math.max(0, tokensBefore - tokensAfter),
    firstKeptEntryId: null,
  };
}

export async function compactMessagesCodexStyle(
  messages: AgentMessage[],
  options: CodexStyleCompactionOptions = {},
): Promise<CompactionResult> {
  if (messages.length === 0) {
    return {
      compacted: false,
      messages,
      removedCount: 0,
      tokenSavings: 0,
    };
  }

  const result = await runCompact(messages, options);
  return {
    compacted: true,
    summary: result.summary,
    messages: result.messages,
    removedCount: result.removedCount,
    tokenSavings: result.tokenSavings,
    firstKeptEntryId: result.firstKeptEntryId,
  };
}

export async function compactMessages(
  messages: AgentMessage[],
  config: Partial<CompactionConfig> = {},
  options: CodexStyleCompactionOptions = {},
): Promise<CompactionResult> {
  const fullOptions = { ...config, ...options };
  return compactMessagesCodexStyle(messages, fullOptions);
}

export async function autoCompact(
  messages: AgentMessage[],
  config: Partial<CompactionConfig> = {},
  options: CodexStyleCompactionOptions = {},
): Promise<CompactionResult> {
  const fullConfig = { ...DEFAULT_COMPACTION_CONFIG, ...config };

  if (!fullConfig.autoCompact) {
    return {
      compacted: false,
      messages,
      removedCount: 0,
      tokenSavings: 0,
    };
  }

  return compactMessagesCodexStyle(messages, { ...fullConfig, ...options });
}

export function createCompactionEntry(
  result: CompactionResult,
  firstKeptEntryId: string,
): CompactionEntry {
  return {
    type: "compaction",
    id: `compaction-${Date.now()}`,
    timestamp: Date.now(),
    summary: result.summary || "",
    firstKeptEntryId,
    tokensBefore: result.tokenSavings + calculateTotalTokens(result.messages),
    tokensAfter: calculateTotalTokens(result.messages),
  };
}

function getMessageText(message: AgentMessage): string {
  if (message.role === "user") {
    return getUserMessageText(message);
  }

  if (message.role === "assistant") {
    return message.content
      .filter((c): c is TextContent => c.type === "text")
      .map((c) => c.text)
      .join(" ");
  }

  if (message.role === "toolResult") {
    return message.content
      .filter((c): c is TextContent => c.type === "text")
      .map((c) => c.text)
      .join(" ");
  }

  return "";
}

function getUserMessageText(message: Extract<AgentMessage, { role: "user" }>): string {
  if (typeof message.content === "string") {
    return message.content;
  }

  return message.content
    .filter((c): c is TextContent => c.type === "text")
    .map((c) => c.text)
    .join(" ");
}

function getAssistantText(message: AssistantMessage): string {
  return message.content
    .filter((c): c is TextContent => c.type === "text")
    .map((c) => c.text)
    .join("")
    .trim();
}

function createSimpleSummary(messages: AgentMessage[]): string {
  const userMessages = collectRealUserMessages(messages);
  const lastUserMessage = userMessages.at(-1);
  const assistantCount = messages.filter((m) => m.role === "assistant").length;
  const toolCount = messages.filter((m) => m.role === "toolResult").length;

  return [
    `- Conversation turns: ${messages.length}`,
    `- Assistant responses: ${assistantCount}`,
    `- Tool results: ${toolCount}`,
    lastUserMessage ? `- Latest user request: ${lastUserMessage}` : "",
  ]
    .filter(Boolean)
    .join("\n");
}

function applyUserTokenBudget(messages: string[], maxTokens: number): string[] {
  if (maxTokens <= 0 || messages.length === 0) {
    return [];
  }

  const selected: string[] = [];
  let remaining = maxTokens;

  for (let i = messages.length - 1; i >= 0; i--) {
    const message = messages[i];
    const messageTokens = approximateTextTokens(message);

    if (messageTokens <= remaining) {
      selected.unshift(message);
      remaining -= messageTokens;
      continue;
    }

    if (selected.length === 0) {
      selected.unshift(truncateTextToTokenBudget(message, remaining));
    }
    break;
  }

  return selected;
}

function applyUserEntryTokenBudget(
  entries: Array<{ entryId: string; text: string }>,
  maxTokens: number,
): Array<{ entryId: string; text: string }> {
  if (maxTokens <= 0 || entries.length === 0) {
    return [];
  }

  const selected: Array<{ entryId: string; text: string }> = [];
  let remaining = maxTokens;

  for (let i = entries.length - 1; i >= 0; i--) {
    const entry = entries[i];
    const messageTokens = approximateTextTokens(entry.text);

    if (messageTokens <= remaining) {
      selected.unshift(entry);
      remaining -= messageTokens;
      continue;
    }

    if (selected.length === 0) {
      selected.unshift({
        entryId: entry.entryId,
        text: truncateTextToTokenBudget(entry.text, remaining),
      });
    }
    break;
  }

  return selected;
}

function truncateTextToTokenBudget(text: string, maxTokens: number): string {
  if (maxTokens <= 0) {
    return "[truncated]";
  }

  const maxChars = Math.max(16, maxTokens * 4);
  if (text.length <= maxChars) {
    return text;
  }

  return `${text.slice(0, Math.max(0, maxChars - 15)).trimEnd()}... [truncated]`;
}

function approximateTextTokens(text: string): number {
  return Math.ceil(text.length / 4);
}

function isSyntheticUserEnvelope(text: string): boolean {
  const trimmed = text.trimStart();
  return (
    trimmed.startsWith("<environment_context>") ||
    trimmed.startsWith("<turn_aborted>") ||
    trimmed.startsWith("# AGENTS.md instructions")
  );
}

function isCompactionCompatibleMessage(message: AgentMessage): boolean {
  if (message.role === "user") return true;
  if (message.role === "assistant") return true;
  if (message.role === "toolResult") return true;
  return false;
}
