import type { AgentTool } from "@pie/agent-core";
import {
  ManageTodoListParamsSchema,
  createTodoStore,
  executeManageTodoList,
  type TodoItem,
} from "@pie/shared-headless-capabilities";

const TOOL_DESCRIPTION = `Manage a structured todo list for multi-step work.

Use this tool when a task benefits from planning, progress tracking, or step-by-step execution.
Always write the full list when updating it.

Preferred status values:
- not-started
- in-progress
- completed`;

export function createManageTodoListTool() {
  const store = createTodoStore();

  const tool: AgentTool = {
    name: "manage_todo_list",
    label: "manage_todo_list",
    description: TOOL_DESCRIPTION,
    parameters: ManageTodoListParamsSchema,
    execute: async (_toolCallId, args: { operation: "read" | "write"; todoList?: TodoItem[] }) => {
      const execution = executeManageTodoList(args, store.read());
      store.restore(execution.nextTodos);
      return execution.result;
    },
  };

  return {
    tool,
    getState() {
      return store.read();
    },
    restore(state: TodoItem[] | undefined) {
      store.restore(state);
    },
    reset() {
      store.clear();
    },
  };
}
