/**
 * Skill loader - loads skills from multiple directories (user + project)
 * Follows pi-mono design: first-loaded wins, collisions tracked
 */

import { FileSystemGateway, getPlatformConfig } from "@pie/platform";
import { parseSkill } from "./parser.js";
import type {
	Skill,
	SkillLoaderOptions,
	SkillRegistryEntry,
	SkillSource,
	ResourceDiagnostic,
	LoadSkillsResult,
} from "./types.js";

/** Skill file extension */
const SKILL_EXTENSION = ".md";
const DIRECTORY_SKILL_ENTRY = "SKILL.md";

/**
 * Get the default skills directory
 * Returns ~/.pie/skills/ on Unix-like systems
 */
export function getDefaultSkillsDir(): string {
	return getPlatformConfig().skillsPath;
}

/**
 * Load skills from a directory
 */
function loadSkillsFromDir(
	dir: string,
	source: SkillSource,
): { skills: SkillRegistryEntry[]; diagnostics: ResourceDiagnostic[] } {
	const skills: SkillRegistryEntry[] = [];
	const diagnostics: ResourceDiagnostic[] = [];

	if (!dir) {
		return { skills, diagnostics };
	}

	const gateway = new FileSystemGateway({
		allowedRoots: [dir, getPlatformConfig().dataPath].filter(Boolean),
	});

	if (!gateway.exists(dir)) {
		return { skills, diagnostics };
	}

	const entries = gateway.readdir(dir);
	for (const entryName of entries) {
		const entryPath = gateway.join(dir, entryName);

		if (gateway.isDirectory(entryPath)) {
			const skillPath = gateway.join(entryPath, DIRECTORY_SKILL_ENTRY);
			if (!gateway.isFile(skillPath)) {
				continue;
			}

			try {
				const content = gateway.readFile(skillPath, "utf-8");
				const skill = parseSkill(content, DIRECTORY_SKILL_ENTRY, skillPath);

				skills.push({
					...skill,
					name: skill.name || entryName,
					loadedAt: Date.now(),
					isActive: false,
					source,
					baseDir: entryPath,
				});
			} catch (e) {
				const message = e instanceof Error ? e.message : "Failed to parse skill";
				diagnostics.push({ type: "warning", message, path: skillPath });
			}
			continue;
		}

		if (!entryName.endsWith(SKILL_EXTENSION)) continue;
		if (!gateway.isFile(entryPath)) continue;

		try {
			const content = gateway.readFile(entryPath, "utf-8");
			const skill = parseSkill(content, entryName, entryPath);

			skills.push({
				...skill,
				loadedAt: Date.now(),
				isActive: false,
				source,
				baseDir: dir,
			});
		} catch (e) {
			const message = e instanceof Error ? e.message : "Failed to parse skill";
			diagnostics.push({ type: "warning", message, path: entryPath });
		}
	}

	return { skills, diagnostics };
}

/**
 * Load skills from multiple directories with collision handling
 * Order: user (global) first, then project - first loaded wins
 */
export function loadSkills(options: {
	userDir: string;
	projectDir: string;
}): LoadSkillsResult {
	const { userDir, projectDir } = options;
	const skillMap = new Map<string, SkillRegistryEntry>();
	const allDiagnostics: ResourceDiagnostic[] = [];

	// 1. Load user (global) skills first - higher priority
	const userResult = loadSkillsFromDir(userDir, "user");
	allDiagnostics.push(...userResult.diagnostics);
	for (const skill of userResult.skills) {
		skillMap.set(skill.name, skill);
	}

	// 2. Load project skills - skip if name collision
	const projectResult = loadSkillsFromDir(projectDir, "project");
	for (const skill of projectResult.skills) {
		if (skillMap.has(skill.name)) {
			// Record collision - user skill wins
			const existing = skillMap.get(skill.name)!;
			allDiagnostics.push({
				type: "collision",
				message: `Skill "${skill.name}" collision: user skill takes precedence`,
				path: skill.filePath!,
				collision: {
					resourceType: "skill",
					name: skill.name,
					winnerPath: existing.filePath!,
					loserPath: skill.filePath!,
				},
			});
		} else {
			skillMap.set(skill.name, skill);
		}
	}
	allDiagnostics.push(...projectResult.diagnostics);

	return {
		skills: Array.from(skillMap.values()),
		diagnostics: allDiagnostics,
	};
}

/**
 * Format skills for system prompt in XML format
 * Similar to pi-mono's formatSkillsForPrompt
 */
export function formatSkillsForPrompt(skills: Skill[]): string {
	if (skills.length === 0) {
		return "";
	}

	const lines = [
		"\n\nThe following skills provide specialized instructions for specific tasks.",
		"Use the read tool to load a skill's file when the task matches its description.",
		"When a skill file references a relative path, resolve it against the skill directory.",
		"",
		"<available_skills>",
	];

	for (const skill of skills) {
		lines.push("  <skill>");
		lines.push(`    <name>${escapeXml(skill.name)}</name>`);
		lines.push(`    <description>${escapeXml(skill.description)}</description>`);
		lines.push(`    <location>${escapeXml(skill.filePath || "")}</location>`);
		lines.push("  </skill>");
	}

	lines.push("</available_skills>");

	return lines.join("\n");
}

function escapeXml(str: string): string {
	return str
		.replace(/&/g, "&amp;")
		.replace(/</g, "&lt;")
		.replace(/>/g, "&gt;")
		.replace(/"/g, "&quot;")
		.replace(/'/g, "&apos;");
}

/**
 * Legacy SkillLoader class for backward compatibility
 * Prefer using loadSkills() directly
 */
export class SkillLoader {
	private userDir: string;
	private projectDir: string;
	private cache?: Map<string, SkillRegistryEntry>;
	private loaded = false;

	constructor(options: SkillLoaderOptions = {}) {
		this.userDir = options.skillsDir || "";
		this.projectDir = "";
		if (options.cache !== false) {
			this.cache = new Map();
		}
	}

	/**
	 * Load all skills from configured directories
	 */
	loadAll(): LoadSkillsResult {
		const result = loadSkills({ userDir: this.userDir, projectDir: this.projectDir });
		if (this.cache) {
			this.cache.clear();
			for (const skill of result.skills) {
				this.cache.set(skill.name, skill);
			}
		}
		this.loaded = true;
		return result;
	}

	/**
	 * Load a skill by name from the directory
	 */
	loadSkill(name: string): SkillRegistryEntry | null {
		if (this.cache?.has(name)) {
			return this.cache.get(name)!;
		}

		// Load from user directory
		if (this.userDir) {
			const gateway = new FileSystemGateway({
				allowedRoots: [this.userDir, getPlatformConfig().dataPath].filter(Boolean),
			});
			const filePath = gateway.join(this.userDir, `${name}.md`);
			if (gateway.isFile(filePath)) {
				try {
					const content = gateway.readFile(filePath, "utf-8");
					const skill = parseSkill(content, `${name}.md`, filePath);
					const entry: SkillRegistryEntry = {
						...skill,
						loadedAt: Date.now(),
						isActive: false,
						source: "user",
						baseDir: this.userDir,
					};
					this.cache?.set(name, entry);
					return entry;
				} catch (e) {
					// Ignore load errors
				}
			}
		}
		return null;
	}

	/**
	 * List all available skill names
	 */
	listSkillNames(): string[] {
		if (!this.loaded) {
			this.loadAll();
		}
		return this.cache ? Array.from(this.cache.keys()) : [];
	}

	hasSkill(name: string): boolean {
		return this.loadSkill(name) !== null;
	}

	/**
	 * Register a skill directly (for project-local skills)
	 */
	registerSkill(skill: Skill & { source?: SkillSource; baseDir?: string }): void {
		if (this.cache) {
			this.cache.set(skill.name, {
				...skill,
				loadedAt: Date.now(),
				isActive: false,
				source: skill.source || "path",
				baseDir: skill.baseDir || "",
			});
		}
	}

	/**
	 * Get a cached skill by name
	 */
	getSkill(name: string): SkillRegistryEntry | undefined {
		return this.cache?.get(name);
	}

	/**
	 * Get all cached skills
	 */
	getAllSkills(): SkillRegistryEntry[] {
		return this.cache ? Array.from(this.cache.values()) : [];
	}
}

/**
 * Create a skill loader instance
 */
export function createSkillLoader(options?: SkillLoaderOptions): SkillLoader {
	return new SkillLoader(options);
}
