import {
  createSkillLoader,
  formatSkillsForPrompt as formatFrameworkSkillsForPrompt,
  parseSkill,
  type SkillRegistryEntry,
} from "@pie/agent-framework";

declare const CS: any;

export interface LoadedSkill {
  name: string;
  description: string;
  source: "builtin" | "project";
  content?: string;
  path?: string;
}

let hasLoggedEmptySkillScan = false;

function normalizePath(path: string): string {
  return String(path ?? "").replace(/\\/g, "/");
}

function parseBridgePathArray(methodName: "getSkillSearchPathsJson" | "getExtensionSearchPathsJson"): string[] {
  const raw = (globalThis as any).pieBridge?.[methodName]?.();
  if (typeof raw !== "string" || raw.trim().length === 0) {
    return [];
  }

  try {
    const parsed = JSON.parse(raw);
    return Array.isArray(parsed)
      ? parsed.map((entry) => normalizePath(String(entry ?? ""))).filter((entry) => entry.length > 0)
      : [];
  } catch {
    return [];
  }
}

export function getSkillSearchPaths(_projectRoot: string): string[] {
  return parseBridgePathArray("getSkillSearchPathsJson");
}

export function getExtensionSearchPaths(_projectRoot: string): string[] {
  return parseBridgePathArray("getExtensionSearchPathsJson");
}

function logEmptySkillScan(projectRoot: string, skillDirs: string[]): void {
  if (hasLoggedEmptySkillScan) return;
  hasLoggedEmptySkillScan = true;

  try {
    const diagnostics = skillDirs.length === 0
      ? ["(no skill search paths configured)"]
      : skillDirs.map((skillsDir) => {
          const exists = CS.System.IO.Directory.Exists(skillsDir);
          if (!exists) {
            return `${normalizePath(String(skillsDir))} [missing]`;
          }

          const directories = CS.System.IO.Directory.GetDirectories(skillsDir);
          const files = CS.System.IO.Directory.GetFiles(skillsDir, "*.md");
          return `${normalizePath(String(skillsDir))} [dirs=${directories.Length}, md=${files.Length}]`;
        });

    CS.Pie.PieDiagnostics.Verbose(
      `[pie/skills] No project skills found. projectRoot=${normalizePath(projectRoot)} searchPaths=${diagnostics.join("; ")}`
    );
  } catch {
    // Ignore diagnostics errors so skill loading stays non-fatal.
  }
}

function registerSkillFile(
  loader: ReturnType<typeof createSkillLoader>,
  skillPath: string,
  fileName: string,
  baseDir: string,
): void {
  if (!CS.System.IO.File.Exists(skillPath)) {
    return;
  }

  try {
    const content = String(CS.System.IO.File.ReadAllText(skillPath) ?? "");
    const parsed = parseSkill(content, fileName, normalizePath(skillPath));
    loader.registerSkill({
      ...parsed,
      source: "project",
      baseDir: normalizePath(baseDir),
    });
  } catch {
    // Ignore malformed skill files in Unity for now to preserve current non-fatal behavior.
  }
}

export function createUnitySkillLoader(projectRoot: string) {
	const loader = createSkillLoader({ skillsDir: "" });
  const skillDirs = getSkillSearchPaths(projectRoot);

  for (const skillsDir of skillDirs) {
    if (!CS.System.IO.Directory.Exists(skillsDir)) continue;

    const directories = CS.System.IO.Directory.GetDirectories(skillsDir);
    for (let i = 0; i < directories.Length; i++) {
      const dir = typeof directories.get_Item === "function" ? directories.get_Item(i) : directories[i];
      const name = String(CS.System.IO.Path.GetFileName(dir) ?? "");
      if (!name) continue;

      const skillPath = CS.System.IO.Path.Combine(dir, "SKILL.md");
      registerSkillFile(loader, skillPath, "SKILL.md", String(dir));
    }

    const files = CS.System.IO.Directory.GetFiles(skillsDir, "*.md");
    for (let i = 0; i < files.Length; i++) {
      const filePath = typeof files.get_Item === "function" ? files.get_Item(i) : files[i];
      const fileName = String(CS.System.IO.Path.GetFileName(filePath) ?? "");
      if (!fileName) continue;
      registerSkillFile(loader, String(filePath), fileName, skillsDir);
    }
  }

  if (loader.getAllSkills().length === 0) {
    logEmptySkillScan(projectRoot, skillDirs);
  }

  return loader;
}

function toLoadedSkill(skill: SkillRegistryEntry): LoadedSkill {
  return {
    name: skill.name,
    description: skill.description,
    source: "project",
    content: skill.prompt,
    path: skill.filePath ? normalizePath(skill.filePath) : undefined,
  };
}

export function getAvailableSkills(projectRoot: string): LoadedSkill[] {
  return createUnitySkillLoader(projectRoot)
    .getAllSkills()
    .map(toLoadedSkill);
}

export function formatSkillsForPrompt(skills: LoadedSkill[]): string {
  return formatFrameworkSkillsForPrompt(
    skills.map((skill) => ({
      name: skill.name,
      displayName: skill.name,
      description: skill.description,
      prompt: skill.content || "",
      filePath: skill.path,
    })),
  );
}

export function readSkillContent(projectRoot: string, name: string): LoadedSkill | null {
  const loader = createUnitySkillLoader(projectRoot);
  const skill = loader.getSkill(name) || loader.loadSkill(name);
  if (!skill) {
    return null;
  }

  return toLoadedSkill(skill);
}
