import type { InteractionRequest, InteractionResponse } from "./shared/types.js";

export class InteractionUnavailableError extends Error {
	request: InteractionRequest;

	constructor(message: string, request: InteractionRequest) {
		super(message);
		this.name = "InteractionUnavailableError";
		this.request = request;
	}
}

export type InteractionHandler = (request: InteractionRequest) => Promise<InteractionResponse> | InteractionResponse;

let currentInteractionHandler: InteractionHandler | null = null;

export function registerInteractionHandler(handler: InteractionHandler | null): void {
	currentInteractionHandler = handler;
}

export function getInteractionHandler(): InteractionHandler | null {
	return currentInteractionHandler;
}

export function hasInteractionHandler(): boolean {
	return currentInteractionHandler !== null;
}

export function clearInteractionHandler(): void {
	currentInteractionHandler = null;
}

export async function requestInteraction(request: InteractionRequest): Promise<InteractionResponse> {
	if (!currentInteractionHandler) {
		throw new InteractionUnavailableError(
			`No interaction handler registered for request type: ${request.type}`,
			request,
		);
	}

	return await currentInteractionHandler(request);
}
