export const KIMI_MODEL_DEFINITIONS = BUILTIN_MODEL_DEFINITIONS["kimi-cn"];
export const GLM_MODEL_DEFINITIONS = BUILTIN_MODEL_DEFINITIONS.bigmodel;

export function getBuiltInModels(): Model<Api>[] {
	const models: Model<Api>[] = [];
	for (const [provider, providerModels] of Object.entries(BUILTIN_MODEL_DEFINITIONS)) {
		for (const [id, model] of Object.entries(providerModels)) {
			models.push({
				id,
				...(model as Omit<Model<Api>, "id">),
				provider,
			});
		}
	}
	return models;
}
